#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 351

int compare(const void *a, const void *b) {
    char *str1 = *(char **)a;
    char *str2 = *(char **)b;
    return strcmp(str1, str2);
}

char **generateBinaryStrings(int N, int K) {
    int count = 0;
    char **binaryStrings = (char **)malloc(1000000 * sizeof(char *));
    for (int i = 0; i < (1 << N); i++) {
        int ones = 0;
        char *str = (char *)malloc((N + 1) * sizeof(char));
        for (int j = 0; j < N; j++) {
            if ((i & (1 << j))) {
                str[j] = '1';
                ones++;
            } else {
                str[j] = '0';
            }
        }
        str[N] = '\0';
        if (ones == K) {
            binaryStrings[count] = str;
            count++;
        } else {
            free(str);
        }
    }
    binaryStrings[count] = NULL;
    return binaryStrings;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, M;
        scanf("%d %d %d", &N, &K, &M);
        char **binaryStrings = generateBinaryStrings(N, K);
        int count = 0;
        while (binaryStrings[count] != NULL) count++;
        if (M > count) {
            printf("-1\n");
        } else {
            qsort(binaryStrings, count, sizeof(char *), compare);
            printf("%s\n", binaryStrings[M - 1]);
        }
        for (int i = 0; i < count; i++) {
            free(binaryStrings[i]);
        }
        free(binaryStrings);
    }
    return 0;
}

