#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
using namespace std;

vector<string> generateBinaryStrings(int N, int K) {
    vector<string> binaryStrings;
    for (int i = 0; i < (1 << N); i++) {
        string str = "";
        int ones = 0;
        for (int j = 0; j < N; j++) {
            if ((i & (1 << j))) {
                str += '1';
                ones++;
            } else {
                str += '0';
            }
        }
        if (ones == K) {
            binaryStrings.push_back(str);
        }
    }
    return binaryStrings;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, K, M;
        cin >> N >> K >> M;
        vector<string> binaryStrings = generateBinaryStrings(N, K);
        if (M > binaryStrings.size()) {
            cout << -1 << endl;
        } else {
            sort(binaryStrings.begin(), binaryStrings.end());
            cout << binaryStrings[M - 1] << endl;
        }
    }
    return 0;
}

