import sys
import itertools

def generate_binary_strings(N, K):
    binary_strings = []
    for bits in itertools.product('01', repeat=N):
        if bits.count('1') == K:
            binary_strings.append(''.join(bits))
    return binary_strings

T = int(sys.stdin.readline().strip())
for _ in range(T):
    N, K, M = map(int, sys.stdin.readline().strip().split())
    binary_strings = generate_binary_strings(N, K)
    if M > len(binary_strings):
        print(-1)
    else:
        binary_strings.sort()
        print(binary_strings[M - 1])

